INSERT INTO knowledge_articles (title, slug, category, content, views) VALUES
('痔疮的类型与分类', 'types', 'types', E'# 痔疮的类型与分类\n\n痔疮是肛门直肠底部及肛门黏膜的静脉丛发生曲张而形成的一个或多个柔软的静脉团。根据发生部位的不同，痔疮可分为以下几种类型：\n\n## 内痔\n\n位于齿状线以上，由直肠上静脉丛曲张形成。表面为黏膜覆盖。\n\n**主要症状：**\n- 便血（鲜红色，无痛性）\n- 痔核脱出\n- 肛门坠胀感\n\n**分期：**\n- Ⅰ期：便血，无脱出\n- Ⅱ期：便血，便时脱出，便后自行回纳\n- Ⅲ期：偶有便血，脱出需手托回纳\n- Ⅳ期：长期脱出，不能回纳\n\n## 外痔\n\n位于齿状线以下，由直肠下静脉丛曲张形成。表面为皮肤覆盖。\n\n**主要类型：**\n- **血栓性外痔**：突然发作，疼痛剧烈\n- **结缔组织性外痔**：皮赘样，一般无痛\n- **静脉曲张性外痔**：排便时增大，便后缩小\n- **炎性外痔**：红肿疼痛\n\n## 混合痔\n\n内痔和外痔在同一方位相互沟通融合，形成一整体。兼有内痔和外痔的症状。\n\n## 及时就医\n\n如果出现以下情况，建议及时就医：\n- 便血持续或量大\n- 剧烈疼痛\n- 痔核嵌顿不能回纳\n- 影响正常生活', 1250),
